import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Check, Zap, Crown, Leaf } from 'lucide-react';
import { getPlans } from '../api/services';

const Plans = () => {
  const [plans, setPlans] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchPlans = async () => {
      try {
        const response = await getPlans();
        setPlans(response.data);
      } catch (error) {
        console.error('Error fetching plans:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchPlans();
  }, []);

  const comparisonFeatures = [
    { name: 'Meals per Week', basic: '3', standard: '5', premium: 'Custom' },
    { name: 'Free Delivery', basic: true, standard: true, premium: true },
    { name: 'Customizable Meals', basic: false, standard: true, premium: true },
    { name: 'Nutritionist Consultation', basic: false, standard: false, premium: true },
    { name: 'Mobile App Access', basic: true, standard: true, premium: true },
    { name: 'Priority Support', basic: false, standard: true, premium: true },
    { name: 'Meal Tracking', basic: false, standard: true, premium: true },
    { name: 'Recipe Videos', basic: false, standard: false, premium: true },
  ];

  return (
    <div className="min-h-screen bg-neutral-bg py-12 px-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center mb-16"
        >
          <h1 className="text-5xl font-poppins font-bold text-dark-text mb-4">
            Choose Your Plan
          </h1>
          <p className="text-xl text-gray-600">
            Flexible subscription options tailored to your fitness goals
          </p>
        </motion.div>

        {/* Plans Grid */}
        {loading ? (
          <div className="text-center py-12">
            <p className="text-gray-600">Loading plans...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-20">
            {plans.map((plan, index) => (
              <PlanCard
                key={plan.id}
                plan={plan}
                isPopular={index === 1}
              />
            ))}
          </div>
        )}

        {/* Comparison Table */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          className="bg-white rounded-2xl shadow-premium overflow-hidden"
        >
          <div className="p-8">
            <h2 className="text-3xl font-poppins font-bold text-dark-text mb-8">
              Plan Comparison
            </h2>

            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b-2 border-gray-200">
                    <th className="text-left py-4 px-4 font-poppins font-bold text-dark-text">
                      Features
                    </th>
                    <th className="text-center py-4 px-4 font-poppins font-bold text-dark-text">
                      Basic
                    </th>
                    <th className="text-center py-4 px-4 font-poppins font-bold text-primary">
                      Standard
                    </th>
                    <th className="text-center py-4 px-4 font-poppins font-bold text-dark-text">
                      Premium
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {comparisonFeatures.map((feature, index) => (
                    <motion.tr
                      key={index}
                      initial={{ opacity: 0, x: -20 }}
                      whileInView={{ opacity: 1, x: 0 }}
                      transition={{ delay: index * 0.05 }}
                      className="border-b border-gray-100 hover:bg-neutral-bg transition-colors"
                    >
                      <td className="py-4 px-4 font-inter text-dark-text">
                        {feature.name}
                      </td>
                      <td className="py-4 px-4 text-center">
                        {typeof feature.basic === 'boolean' ? (
                          feature.basic ? (
                            <Check className="inline text-primary" size={20} />
                          ) : (
                            <X className="inline text-gray-300" size={20} />
                          )
                        ) : (
                          <span className="font-semibold text-dark-text">
                            {feature.basic}
                          </span>
                        )}
                      </td>
                      <td className="py-4 px-4 text-center">
                        {typeof feature.standard === 'boolean' ? (
                          feature.standard ? (
                            <Check className="inline text-primary" size={20} />
                          ) : (
                            <X className="inline text-gray-300" size={20} />
                          )
                        ) : (
                          <span className="font-semibold text-dark-text">
                            {feature.standard}
                          </span>
                        )}
                      </td>
                      <td className="py-4 px-4 text-center">
                        {typeof feature.premium === 'boolean' ? (
                          feature.premium ? (
                            <Check className="inline text-primary" size={20} />
                          ) : (
                            <X className="inline text-gray-300" size={20} />
                          )
                        ) : (
                          <span className="font-semibold text-dark-text">
                            {feature.premium}
                          </span>
                        )}
                      </td>
                    </motion.tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </motion.div>

        {/* FAQ Section */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          className="mt-20"
        >
          <h2 className="text-3xl font-poppins font-bold text-dark-text mb-8 text-center">
            Frequently Asked Questions
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {[
              {
                q: 'Can I change my plan anytime?',
                a: 'Yes, you can upgrade or downgrade your plan at any time. Changes take effect from the next billing cycle.',
              },
              {
                q: 'Is there a contract?',
                a: 'No contracts required. Cancel anytime with no penalties or hidden fees.',
              },
              {
                q: 'Do you offer refunds?',
                a: 'We offer a 7-day money-back guarantee if you\'re not satisfied with our service.',
              },
              {
                q: 'Can I customize my meals?',
                a: 'Yes, with Standard and Premium plans you can customize your meal preferences.',
              },
            ].map((faq, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                className="bg-white rounded-2xl p-6 shadow-premium"
              >
                <h3 className="font-poppins font-bold text-dark-text mb-3">
                  {faq.q}
                </h3>
                <p className="text-gray-600">{faq.a}</p>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </div>
    </div>
  );
};

export default Plans;
